WITH table_columns AS (SELECT n.nspname AS table_schema, CASE c.relkind WHEN 'r' THEN 'TABLE' WHEN 'p' THEN 'PARTITIONED_TABLE' WHEN 'm' THEN 'MATERIALIZED_VIEW' ELSE 'UNCATEGORIZED' END AS table_type, c.relname AS table_name, a.attname AS column_name, t.typname AS data_type, a.atttypmod AS type_modifier FROM pg_attribute AS a JOIN pg_class AS c ON a.attrelid = c.oid JOIN pg_namespace AS n ON n.oid = c.relnamespace JOIN pg_type AS t ON a.atttypid = t.oid WHERE a.attnum > 0 AND NOT a.attisdropped AND n.nspname <> ALL(ARRAY['pg_catalog', 'information_schema']) AND NOT n.nspname ~ '^pg_toast' AND c.relkind = ANY(ARRAY['r', 'p', 'm'])), src AS (SELECT a.table_schema, a.table_type, a.table_name, a.data_type, a.type_modifier, COUNT(a.data_type) AS data_type_count FROM table_columns AS a GROUP BY a.table_schema, a.table_type, a.table_name, a.data_type, a.type_modifier) SELECT CHR(34) || :PKEY || CHR(34) AS pkey, CHR(34) || :DMA_SOURCE_ID || CHR(34) AS dma_source_id, CHR(34) || :DMA_MANUAL_ID || CHR(34) AS dma_manual_id, src.table_schema, src.table_type, src.table_name, src.data_type, src.type_modifier, src.data_type_count FROM src